args.content:
- id: match-weather
  type: match-up
  focus: Weather and nature words
  items:
  - { term: "пого́да", definition: "weather" }
  - { term: "дощ", definition: "rain" }
  - { term: "сніг", definition: "snow" }
  - { term: "со́нце", definition: "sun" }
  - { term: "тепло́", definition: "warm" }
  - { term: "хо́лодно", definition: "cold" }
  - { term: "спекотно", definition: "hot" }
  - { term: "прохоло́дно", definition: "cool" }
  - { term: "весна́", definition: "spring" }
  - { term: "зима́", definition: "winter" }
  - { term: "лі́то", definition: "summer" }
  - { term: "о́сінь", definition: "autumn" }
  - { term: "ліс", definition: "forest" }
  - { term: "го́ри", definition: "mountains" }
  - { term: "мо́ре", definition: "sea" }
  - { term: "хма́ра", definition: "cloud" }
  - { term: "ві́тер", definition: "wind" }
  - { term: "о́зеро", definition: "lake" }
  - { term: "рі́чка", definition: "river" }
  - { term: "прогно́з", definition: "forecast" }
  - { term: "яскра́ве", definition: "bright" }
  - { term: "си́льний", definition: "strong" }
  - { term: "га́рний", definition: "good" }
  - { term: "пога́ний", definition: "bad" }
  - { term: "чудо́во", definition: "wonderful" }
  - { term: "сього́дні", definition: "today" }
  - { term: "за́втра", definition: "tomorrow" }
  - { term: "на ву́лиці", definition: "outside" }
  - { term: "взи́мку", definition: "in winter" }
  - { term: "навесні́", definition: "in spring" }

- id: match-seasons
  type: match-up
  focus: Match weather to seasons
  items:
  - { term: "взи́мку", definition: "in winter" }
  - { term: "навесні́", definition: "in spring" }
  - { term: "влі́тку", definition: "in summer" }
  - { term: "восени́", definition: "in autumn" }
  - { term: "ду́же хо́лодно", definition: "very cold" }
  - { term: "тепло́", definition: "warm" }
  - { term: "ду́же спекотно", definition: "very hot" }
  - { term: "прохоло́дно", definition: "cool" }
  - { term: "бага́то сні́гу", definition: "a lot of snow" }
  - { term: "йде сніг", definition: "it is snowing" }
  - { term: "світи́ть со́нце", definition: "the sun is shining" }
  - { term: "си́льний дощ", definition: "heavy rain" }
  - { term: "зима́", definition: "winter" }
  - { term: "весна́", definition: "spring" }
  - { term: "лі́то", definition: "summer" }
  - { term: "о́сінь", definition: "autumn" }
  - { term: "на мо́рі", definition: "at the sea" }
  - { term: "у лі́сі", definition: "in the forest" }
  - { term: "в го́рах", definition: "in the mountains" }
  - { term: "бі́ля річки́", definition: "near the river" }

- id: fill-weather
  type: fill-in
  focus: Complete weather descriptions
  items:
  - { sentence: "Сього́дні дуже {хо́лодно|со́нце|ві́тер}.", translation: "It is very cold today." }
  - { sentence: "На ву́лиці {тепло́|хма́ра|прогно́з}.", translation: "It is warm outside." }
  - { sentence: "За́втра бу́де {спекотно|зима|рі́чка}.", translation: "Tomorrow it will be hot." }
  - { sentence: "Восени́ {прохоло́дно|спекотно|тепло́}.", translation: "In autumn it is cool." }
  - { sentence: "{Йде|Робить|Іде} сильний дощ.", translation: "Heavy rain is falling." }
  - { sentence: "Взи́мку {йде|світить|буде} сніг.", translation: "It snows in winter." }
  - { sentence: "Світи́ть яскра́ве {со́нце|хма́ра|ві́тер}.", translation: "The bright sun is shining." }
  - { sentence: "Сього́дні си́льний {ві́тер|дощ|со́нце}.", translation: "There is a strong wind today." }
  - { sentence: "Влі́тку на {мо́рі|снігу|озері} ду́же спекотно.", translation: "In summer it is very hot at the sea." }
  - { sentence: "Взи́мку в {го́рах|річці|дощі} бага́то сні́гу.", translation: "In winter there is a lot of snow in the mountains." }
  - { sentence: "Навесні́ бі́ля річки́ та на о́зері {тепло́|хо́лодно|погано}.", translation: "In spring it is warm near the river and at the lake." }
  - { sentence: "Восени́ у лі́сі {прохоло́дно|спекотно|погано}, там га́рна приро́да.", translation: "In autumn it is cool in the forest, the nature is beautiful there." }
  - { sentence: "Сього́дні хо́лодно. Ми не {гуля́ємо|йдемо|світимо}.", translation: "Today it is cold. We are not walking." }
  - { sentence: "Йде си́льний дощ. Я не {ї́ду|гуляю|роби́ть} в го́ри.", translation: "Heavy rain is falling. I am not going to the mountains." }
  - { sentence: "Сього́дні тепло́. Вони́ {йдуть|їдуть|світять} у ліс.", translation: "It is warm today. They are going to the forest." }

- id: fill-conversation
  type: fill-in
  focus: Weather conversations
  items:
  - { sentence: "Приві́т! {Яка|Що|Де} сього́дні пого́да?", translation: "Hi! What is the weather like today?" }
  - { sentence: "Сього́дні {пога́на|сильний|великий} пого́да.", translation: "Today is bad weather." }
  - { sentence: "Вели́ка хма́ра і {си́льний|яскравий|холодно} ві́тер.", translation: "A big cloud and a strong wind." }
  - { sentence: "А що там за {прогно́зом|со́нцем|ві́тром} на за́втра?", translation: "And what is in the forecast for tomorrow?" }
  - { sentence: "Чи {бу́де|йде|світить} дощ?", translation: "Will there be rain?" }
  - { sentence: "Чудо́во! Бу́де га́рний {прогно́з|со́нце|дощ}.", translation: "Wonderful! There will be a good forecast." }

